class Solution:
    def maxPartitionsAfterOperations(self, s, k):
        def count_partitions(t, k):
            cur = 0
            parts = 1
            for c in t:
                bit = 1 << (ord(c) - ord('a'))
                if bin(cur | bit).count('1') > k:
                    parts += 1
                    cur = bit
                else:
                    cur |= bit
            return parts
        n = len(s)
        best = count_partitions(s, k)
        for i in range(n):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                if c != s[i]:
                    t = s[:i] + c + s[i+1:]
                    best = max(best, count_partitions(t, k))
        return best

