var maxPartitionsAfterOperations = function(s, k) {
    function countParts(t) {
        let cur = 0, parts = 1;
        for (const c of t) {
            const bit = 1 << (c.charCodeAt(0) - 97);
            if (popcount(cur | bit) > k) { parts++; cur = bit; }
            else cur |= bit;
        }
        return parts;
    }
    function popcount(x) {
        let c = 0; while (x) { c += x & 1; x >>>= 1; } return c;
    }
    const n = s.length;
    let best = countParts(s);
    for (let i = 0; i < n; i++) {
        for (let ci = 0; ci < 26; ci++) {
            const c = String.fromCharCode(97 + ci);
            if (c !== s[i]) {
                const t = s.slice(0, i) + c + s.slice(i+1);
                best = Math.max(best, countParts(t));
            }
        }
    }
    return best;
};
